frappe.listview_settings['Student Kit Issue'] = {
    get_indicator: function(doc) {
        if (doc.status === 'Delivered') {
            return [__('Delivered'), 'green', 'status,=,Delivered'];
        } else if (doc.status === 'Pending') {
            return [__('Pending'), 'yellow', 'status,=,Pending'];
        } else if (doc.status === 'Returned') {
            return [__('Returned'), 'red', 'status,=,Returned'];
        }
    }
};
